module top_module(
    input [3:0] A,
    input [3:0] B,
    output reg [4:0] X  // Change output type to reg
);wire [4:0] carry_sum;

    assign carry_sum = A + B;

    always @(*) begin
        if (carry_sum <= 15) begin
            X = {1'b0, carry_sum};
        end else begin
            X = carry_sum;
        end
    end

endmodule
